import React, { useEffect, useState } from "react";
import { Box, Typography, Container, Avatar, Grid } from "@mui/material";
import { motion } from "framer-motion";

const textOptions = ["React.js", "React Native", "Full Stack Development"];

export default function About() {
  const [currentText, setCurrentText] = useState("");
  const [textIndex, setTextIndex] = useState(0);
  const [charIndex, setCharIndex] = useState(0);
  const [isDeleting, setIsDeleting] = useState(false);

  useEffect(() => {
    const currentString = textOptions[textIndex];
    const timeout = setTimeout(() => {
      if (isDeleting) {
        setCurrentText(currentString.substring(0, charIndex - 1));
        setCharIndex(charIndex - 1);
      } else {
        setCurrentText(currentString.substring(0, charIndex + 1));
        setCharIndex(charIndex + 1);
      }

      // If we reach the end of the string, start deleting
      if (!isDeleting && charIndex === currentString.length) {
        setIsDeleting(true);
      } 
      // If we are deleting and reach the start, move to the next string
      else if (isDeleting && charIndex === 0) {
        setIsDeleting(false);
        setTextIndex((textIndex + 1) % textOptions.length);
      }
    }, isDeleting ? 50 : 150); // Adjust typing speed here

    return () => clearTimeout(timeout);
  }, [currentText, charIndex, isDeleting, textIndex]);

  return (
    <Container maxWidth="lg">
      <Grid container alignItems="center" spacing={4} sx={{ py: 8 }}>
        {/* Left Section - Profile Image */}
        <Grid item xs={12} md={5} display="flex" justifyContent="center">
          <Avatar
            alt="Soumya Ranjan Nayak"
            src="assets/soumya.jpg" // Replace with your image path
            sx={{ width: 200, height: 200, boxShadow: 3 }}
          />
        </Grid>

        {/* Right Section - Intro Text */}
        <Grid item xs={12} md={7} style={{ textAlign: "left" }}>
          <Typography variant="h4" gutterBottom fontWeight="bold">
            Hi, I'm Soumya Ranjan Nayak
          </Typography>
          <Typography variant="h5" sx={{ color: "primary.main", fontWeight: "bold" }}>
            A Full Stack Developer specializing in <span style={{ fontWeight: "bold" }}>{currentText}</span>
          </Typography>
          <Typography variant="body1" paragraph sx={{ mt: 2 }}>
            With a passion for building scalable and user-friendly applications, I have honed my expertise in{" "}
            <strong>React.js</strong> for web development and <strong>React Native</strong> for mobile applications.
            My experience spans across frontend and backend technologies, enabling me to create seamless and efficient
            digital solutions.
          </Typography>
          <Typography variant="body1" paragraph>
            I thrive on solving complex problems, optimizing performance, and enhancing user experiences. Whether it's
            crafting pixel-perfect UIs, integrating APIs, or architecting backend systems, I am committed to delivering
            high-quality, maintainable code.
          </Typography>
          <Typography variant="body1">
            Driven by continuous learning and innovation, I stay updated with the latest industry trends and best
            practices. I love collaborating with teams to turn ideas into reality, making technology more intuitive and
            impactful.
          </Typography>
        </Grid>
      </Grid>
    </Container>
  );
}
